const a={required:e=>!!e||"You must enter a value",email:e=>/\S+@\S+\.\S+/.test(e)||"Enter a valid e-mail address",name:e=>/^[a-zA-Z]+(([',. -][a-zA-Z ])?[a-zA-Z]*)*$/.test(e)||"Enter a valid name",phone:e=>/^\+?\d{0,3}[- ]?\(?(\d{3})\)?[- ]?(\d{3})[- ]?(\d{4})$/.test(e)||"Enter a valid phone number",phoneOrBlank:e=>!e||a.phone(e),sameAs:(e,r="Values")=>t=>e===t||`${r} must match`};export{a as r};
